using FlightAPI.Data; using FlightAPI.DTOs; using FlightAPI.Models; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using Microsoft.EntityFrameworkCore;
namespace FlightAPI.Controllers;
[ApiController, Route("api/bookings"), Authorize]
public class BookingsController:ControllerBase{private readonly AppDbContext _db; public BookingsController(AppDbContext db){_db=db;}
[HttpGet] public async Task<IActionResult> Get(int? userId)=>Ok(await _db.Bookings.Include(b=>b.Flight).Include(b=>b.Seat).Include(b=>b.User).Where(b=>!userId.HasValue||b.UserId==userId).ToListAsync());
[HttpPost] public async Task<IActionResult> Create(BookingDto d){ using var tx=await _db.Database.BeginTransactionAsync(); var seat=await _db.Seats.FirstOrDefaultAsync(s=>s.Id==d.SeatId&&s.FlightId==d.FlightId); if(seat==null)return BadRequest(new{message="Invalid seat"}); if(seat.IsBooked)return Conflict(new{message="Seat already booked"}); var flight=await _db.Flights.FindAsync(d.FlightId); if(flight==null)return BadRequest(new{message="Flight not found"}); seat.IsBooked=true; var b=new Booking{ReferenceNo="FB-"+DateTime.UtcNow.ToString("yyyyMMddHHmmss")+Random.Shared.Next(100,999),UserId=d.UserId,FlightId=d.FlightId,SeatId=d.SeatId,PassengerName=d.PassengerName,Status="Confirmed"}; _db.Bookings.Add(b); await _db.SaveChangesAsync(); _db.Payments.Add(new Payment{BookingId=b.Id,Amount=flight.Price,Method=d.PaymentMethod,Status="Paid"}); await _db.SaveChangesAsync(); await tx.CommitAsync(); return Ok(new{message="Booking confirmed",booking=b});}
[HttpPut("{id}/cancel")] public async Task<IActionResult> Cancel(int id){var b=await _db.Bookings.FindAsync(id); if(b==null)return NotFound(); b.Status="Cancelled"; var s=await _db.Seats.FindAsync(b.SeatId); if(s!=null)s.IsBooked=false; await _db.SaveChangesAsync(); return Ok(new{message="Booking cancelled"});}
[HttpGet("{id}/ticket")] public async Task<IActionResult> Ticket(int id)=>Ok(await _db.Bookings.Include(b=>b.Flight).Include(b=>b.Seat).Include(b=>b.User).FirstOrDefaultAsync(b=>b.Id==id));}
